from collections import defaultdict
def a(n):
    states = {1: 1}
    for k in range(1, n+1):
        new = defaultdict(int)
        limit = 2**k
        for P, c in states.items():
            new[P] += c
            P1 = P*(k+1)
            if P1 <= limit:
                new[P1] += c
        states = dict(new)
    return sum(states.values())
print([a(n) for n in range(30)])

